# engine/argot/research/signal/phase14/filters/test_autogenerated_filter.py
"""Tests for is_auto_generated — marker coverage, window boundaries, edge cases."""

from __future__ import annotations

import pytest

from argot.research.signal.phase14.filters.autogenerated import (
    _ALL_MARKERS,
    is_auto_generated,
)


# ---------------------------------------------------------------------------
# Edge cases
# ---------------------------------------------------------------------------


def test_empty_string_returns_false() -> None:
    assert is_auto_generated("") is False


def test_none_equivalent_empty_returns_false() -> None:
    # The function accepts str; callers guard None before calling.
    # Verify empty string is handled.
    assert is_auto_generated("") is False


def test_single_line_no_marker_returns_false() -> None:
    assert is_auto_generated("x = 1") is False


def test_single_line_with_marker_returns_true() -> None:
    assert is_auto_generated("# auto-generated") is True


def test_non_ascii_source_no_marker() -> None:
    src = "# こんにちは\ndef foo():\n    pass\n"
    assert is_auto_generated(src) is False


def test_non_ascii_source_with_marker() -> None:
    src = "# こんにちは — auto-generated\ndef foo():\n    pass\n"
    assert is_auto_generated(src) is True


# ---------------------------------------------------------------------------
# Window boundary tests
# ---------------------------------------------------------------------------


def _make_src(marker: str, line_number: int) -> str:
    """Place *marker* at 1-indexed *line_number* in a filler file."""
    lines = [f"# line {i}" for i in range(1, 200)]
    lines[line_number - 1] = f"# {marker}"
    return "\n".join(lines)


def test_marker_at_line_1_detected() -> None:
    src = _make_src("auto-generated", 1)
    assert is_auto_generated(src) is True


def test_marker_at_line_40_detected() -> None:
    src = _make_src("auto-generated", 40)
    assert is_auto_generated(src) is True


def test_marker_at_line_41_not_detected() -> None:
    src = _make_src("auto-generated", 41)
    assert is_auto_generated(src) is False


def test_marker_at_line_100_not_detected() -> None:
    src = _make_src("do not edit this file", 100)
    assert is_auto_generated(src) is False


def test_do_not_edit_at_line_50_not_detected() -> None:
    # Spec example: "# TODO: do not edit this function yet" at line 50 → False
    src = _make_src("TODO: do not edit this function yet", 50)
    assert is_auto_generated(src) is False


# ---------------------------------------------------------------------------
# Strong first-10-line rule
# ---------------------------------------------------------------------------


def test_do_not_edit_at_line_1_is_true() -> None:
    src = "# DO NOT EDIT — regenerate with foo.py\ndef foo(): pass"
    assert is_auto_generated(src) is True


def test_do_not_edit_at_line_10_is_true() -> None:
    src = _make_src("do not edit", 10)
    assert is_auto_generated(src) is True


def test_do_not_modify_at_line_10_is_true() -> None:
    src = _make_src("do not modify", 10)
    assert is_auto_generated(src) is True


def test_do_not_edit_at_line_11_still_detected_via_full_marker_list() -> None:
    # "do not edit" is also in _ALL_MARKERS so lines 11–40 still trigger
    src = _make_src("do not edit", 11)
    assert is_auto_generated(src) is True


def test_do_not_edit_at_line_41_not_detected() -> None:
    src = _make_src("do not edit", 41)
    assert is_auto_generated(src) is False


# ---------------------------------------------------------------------------
# Case-insensitive matching
# ---------------------------------------------------------------------------


@pytest.mark.parametrize(
    "variant",
    [
        "AUTO GENERATED",
        "Auto-Generated",
        "AUTOGENERATED",
        "auto_generated",
        "Auto_Generated",
        "AUTO_GENERATED",
    ],
)
def test_case_variants(variant: str) -> None:
    src = f"# {variant}\ndef foo(): pass"
    assert is_auto_generated(src) is True


# ---------------------------------------------------------------------------
# Marker coverage — every marker in _ALL_MARKERS must trigger in head window
# ---------------------------------------------------------------------------


@pytest.mark.parametrize("marker", _ALL_MARKERS)
def test_all_markers_trigger_when_in_head(marker: str) -> None:
    src = f"# {marker}\ndef foo(): pass"
    assert is_auto_generated(src) is True, f"Marker not detected: {marker!r}"


@pytest.mark.parametrize("marker", _ALL_MARKERS)
def test_all_markers_silent_when_outside_head(marker: str) -> None:
    # Put the marker at line 41 (just outside default head_lines=40)
    src = _make_src(marker, 41)
    assert is_auto_generated(src) is False, (
        f"Marker triggered outside head window: {marker!r}"
    )


# ---------------------------------------------------------------------------
# Custom head_lines parameter
# ---------------------------------------------------------------------------


def test_custom_head_lines_smaller_window() -> None:
    # marker at line 10 — visible with head_lines=40, invisible with head_lines=5
    src = _make_src("auto-generated", 10)
    assert is_auto_generated(src, head_lines=5) is False
    assert is_auto_generated(src, head_lines=10) is True


# ---------------------------------------------------------------------------
# Specific tool markers
# ---------------------------------------------------------------------------


def test_generated_by_protoc() -> None:
    assert is_auto_generated("# Generated by protoc -- DO NOT EDIT!\n") is True


def test_generated_by_pydantic() -> None:
    assert is_auto_generated("# generated by pydantic-codegen\n") is True


def test_output_of_marker() -> None:
    # "output of" is intentionally broad; test it triggers
    assert is_auto_generated("# output of unicode_data_generator.py\n") is True


def test_produced_by_marker() -> None:
    assert is_auto_generated("# produced by some tool\n") is True


# ---------------------------------------------------------------------------
# Regression: markers inside docstrings / string literals must NOT fire
# ---------------------------------------------------------------------------


def test_generated_by_in_docstring_returns_false() -> None:
    src = '''\
class Provider:
    """Bank codes and BIC/SWIFT codes generated by this provider."""

    def generate(self) -> str:
        return "BIC"
'''
    assert is_auto_generated(src) is False


def test_generated_by_in_string_literal_returns_false() -> None:
    src = 'x = "generated by some tool"\ndef foo(): pass\n'
    assert is_auto_generated(src) is False


def test_generated_by_in_comment_still_true() -> None:
    src = "# generated by some tool\ndef foo(): pass\n"
    assert is_auto_generated(src) is True
